 47→
 48→        // Register user
 49→        RegisterRequest regReq = new RegisterRequest();
 50→        regReq.setUsername("stateuser");
 51→        regReq.setPassword("password123");
 52→        regReq.setDisplayName("State Test User");
 53→
 54→        mockMvc.perform(post("/api/auth/register")
 55→                        .contentType(MediaType.APPLICATION_JSON)
 56→                        .content(objectMapper.writeValueAsString(regReq)))
 57→                .andExpect(status().isCreated());
 58→
 59→        // Login to get token
 60→        LoginRequest loginReq = new LoginRequest();
 61→        loginReq.setUsername("stateuser");
 62→        loginReq.setPassword("password123");
 63→
 64→        MvcResult loginResult = mockMvc.perform(post("/api/auth/login")
 65→                        .contentType(MediaType.APPLICATION_JSON)
 66→                        .content(objectMapper.writeValueAsString(loginReq)))
 67→                .andExpect(status().isOk())
 68→                .andReturn();
 69→
 70→        token = objectMapper.readTree(loginResult.getResponse().getContentAsString())
 71→                .get("token").asText();
 72→
 73→        // Create a task (initial status = TODO)
 74→        String taskJson = "{\"title\":\"State Machine Test Task\",\"priority\":\"MEDIUM\"}";
 75→
 76→        MvcResult taskResult = mockMvc.perform(post("/api/tasks")
 77→                        .header("Authorization", "Bearer " + token)
 78→                        .contentType(MediaType.APPLICATION_JSON)
 79→                        .content(taskJson))
 80→                .andExpect(status().isCreated())
 81→                .andReturn();
 82→
 83→        taskId = objectMapper.readTree(taskResult.getResponse().getContentAsString())
 84→                .get("id").asLong();
 85→    }
