 87→    private Long createFreshTask() throws Exception {
 88→        String taskJson = "{\"title\":\"Fresh Task " + System.nanoTime() + "\",\"priority\":\"LOW\"}";
 89→        MvcResult result = mockMvc.perform(post("/api/tasks")
 90→                        .header("Authorization", "Bearer " + token)
 91→                        .contentType(MediaType.APPLICATION_JSON)
 92→                        .content(taskJson))
 93→                .andExpect(status().isCreated())
 94→                .andReturn();
 95→        return objectMapper.readTree(result.getResponse().getContentAsString())
 96→                .get("id").asLong();
 97→    }
