 99→    private void transitionTo(Long id, String status) throws Exception {
100→        String body = "{\"status\":\"" + status + "\"}";
101→        mockMvc.perform(patch("/api/tasks/" + id + "/status")
102→                        .header("Authorization", "Bearer " + token)
103→                        .contentType(MediaType.APPLICATION_JSON)
104→                        .content(body))
105→                .andExpect(status().isOk());
106→    }
