317→    @Nested
318→    @DisplayName("AC10: updatedAt on transition")
319→    class UpdatedAtTests {
320→
321→        @Test
322→        @DisplayName("AC10: successful transition updates updatedAt")
323→        void successfulTransition_updatesTimestamp() throws Exception {
324→            // Get initial task — updatedAt should be null for a fresh task
325→            MvcResult before = mockMvc.perform(get("/api/tasks/" + taskId)
326→                            .header("Authorization", "Bearer " + token))
327→                    .andExpect(status().isOk())
328→                    .andReturn();
329→
330→            String updatedAtBefore = objectMapper.readTree(
331→                    before.getResponse().getContentAsString()).path("updatedAt").asText(null);
332→
333→            // Transition TODO -> IN_PROGRESS
334→            String body = "{\"status\":\"IN_PROGRESS\"}";
335→            MvcResult after = mockMvc.perform(patch("/api/tasks/" + taskId + "/status")
336→                            .header("Authorization", "Bearer " + token)
337→                            .contentType(MediaType.APPLICATION_JSON)
338→                            .content(body))
339→                    .andExpect(status().isOk())
340→                    .andReturn();
341→
342→            JsonNode afterNode = objectMapper.readTree(after.getResponse().getContentAsString());
343→            String updatedAtAfter = afterNode.path("updatedAt").asText(null);
344→
345→            // updatedAt should now be set (non-null)
346→            org.junit.jupiter.api.Assertions.assertNotNull(updatedAtAfter,
347→                    "updatedAt should be set after transition");
348→            org.junit.jupiter.api.Assertions.assertFalse(updatedAtAfter.isEmpty(),
349→                    "updatedAt should not be empty after transition");
350→        }
351→
352→        @Test
353→        @DisplayName("AC10: failed transition does NOT update updatedAt")
354→        void failedTransition_doesNotUpdateTimestamp() throws Exception {
355→            // Get initial task
356→            MvcResult before = mockMvc.perform(get("/api/tasks/" + taskId)
357→                            .header("Authorization", "Bearer " + token))
358→                    .andExpect(status().isOk())
359→                    .andReturn();
360→
361→            String updatedAtBefore = objectMapper.readTree(
362→                    before.getResponse().getContentAsString()).path("updatedAt").asText(null);
363→
364→            // Attempt illegal transition TODO -> DONE (should fail 400)
365→            String body = "{\"status\":\"DONE\"}";
366→            mockMvc.perform(patch("/api/tasks/" + taskId + "/status")
367→                            .header("Authorization", "Bearer " + token)
368→                            .contentType(MediaType.APPLICATION_JSON)
369→                            .content(body))
370→                    .andExpect(status().isBadRequest());
371→
372→            // Verify updatedAt unchanged
373→            MvcResult after = mockMvc.perform(get("/api/tasks/" + taskId)
374→                            .header("Authorization", "Bearer " + token))
375→                    .andExpect(status().isOk())
376→                    .andReturn();
377→
378→            String updatedAtAfter = objectMapper.readTree(
379→                    after.getResponse().getContentAsString()).path("updatedAt").asText(null);
380→
381→            org.junit.jupiter.api.Assertions.assertEquals(updatedAtBefore, updatedAtAfter,
382→                    "updatedAt should not change on failed transition");
383→        }
384→    }
