554→        @Test
555→        @DisplayName("Complete lifecycle: TODO -> IN_PROGRESS -> DONE -> CLOSED")
556→        void fullLifecycle() throws Exception {
557→            Long freshId = createFreshTask();
558→
559→            // TODO -> IN_PROGRESS
560→            transitionTo(freshId, "IN_PROGRESS");
561→            mockMvc.perform(get("/api/tasks/" + freshId)
562→                            .header("Authorization", "Bearer " + token))
563→                    .andExpect(jsonPath("$.status").value("IN_PROGRESS"));
564→
