566→            transitionTo(freshId, "DONE");
567→            mockMvc.perform(get("/api/tasks/" + freshId)
568→                            .header("Authorization", "Bearer " + token))
569→                    .andExpect(jsonPath("$.status").value("DONE"));
570→
571→            // DONE -> CLOSED
572→            transitionTo(freshId, "CLOSED");
573→            mockMvc.perform(get("/api/tasks/" + freshId)
574→                            .header("Authorization", "Bearer " + token))
575→                    .andExpect(jsonPath("$.status").value("CLOSED"));
576→        }
