15→@Service
16→public class TaskStateMachineService {
17→
18→    private static final Map<TaskStatus, List<TaskStatus>> TRANSITIONS = new EnumMap<>(TaskStatus.class);
19→
20→    static {
21→        TRANSITIONS.put(TaskStatus.TODO, List.of(TaskStatus.IN_PROGRESS));
22→        TRANSITIONS.put(TaskStatus.IN_PROGRESS, List.of(TaskStatus.TODO, TaskStatus.DONE));
23→        TRANSITIONS.put(TaskStatus.DONE, List.of(TaskStatus.CLOSED));
24→        TRANSITIONS.put(TaskStatus.CLOSED, List.of());
25→    }
26→
27→    private final TaskRepository taskRepository;
28→
29→    public TaskStateMachineService(TaskRepository taskRepository) {
30→        this.taskRepository = taskRepository;
31→    }
32→
33→    public TaskResponse updateStatus(Long taskId, String targetStatusStr) {
34→        Task task = findTask(taskId);
35→        TaskStatus targetStatus = TaskStatus.valueOf(targetStatusStr);
36→        TaskStatus currentStatus = task.getStatus();
37→
38→        List<TaskStatus> allowed = TRANSITIONS.getOrDefault(currentStatus, List.of());
39→        if (!allowed.contains(targetStatus)) {
40→            throw new IllegalStateException(
41→                    "Invalid transition from " + currentStatus + " to " + targetStatus);
42→        }
43→
44→        task.setStatus(targetStatus);
45→        Task saved = taskRepository.save(task);
46→        return toResponse(saved);
47→    }
48→
49→    public TransitionResponse getAvailableTransitions(Long taskId) {
50→        Task task = findTask(taskId);
51→        List<String> available = TRANSITIONS.getOrDefault(task.getStatus(), List.of())
52→                .stream()
53→                .map(TaskStatus::name)
54→                .toList();
55→        return new TransitionResponse(task.getStatus().name(), available);
56→    }
57→
58→    private Task findTask(Long taskId) {
59→        return taskRepository.findById(taskId)
60→                .filter(t -> !t.isDeleted())
61→                .orElseThrow(() -> new ResourceNotFoundException("Task not found"));
62→    }
63→
64→    private TaskResponse toResponse(Task task) {
65→        TaskResponse response = new TaskResponse();
66→        response.setId(task.getId());
67→        response.setTitle(task.getTitle());
68→        response.setDescription(task.getDescription());
69→        response.setPriority(task.getPriority());
70→        response.setStatus(task.getStatus().name());
71→        response.setCreatedBy(task.getCreatedBy());
72→        response.setCreatedAt(task.getCreatedAt());
73→        response.setUpdatedAt(task.getUpdatedAt());
74→        return response;
75→    }
