package com.taskflow.controller;

import com.taskflow.dto.ErrorResponse;
import com.taskflow.dto.StatusUpdateRequest;
import com.taskflow.dto.TaskResponse;
import com.taskflow.dto.TransitionResponse;
import com.taskflow.service.TaskStateMachineService;
import jakarta.validation.Valid;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

@RestController
@RequestMapping("/api/tasks")
public class TaskStatusController {

    private final TaskStateMachineService stateMachineService;

    public TaskStatusController(TaskStateMachineService stateMachineService) {
        this.stateMachineService = stateMachineService;
    }

    @PatchMapping("/{id}/status")
    public ResponseEntity<TaskResponse> updateStatus(@PathVariable Long id,
                                                     @Valid @RequestBody StatusUpdateRequest request) {
        TaskResponse response = stateMachineService.updateStatus(id, request.getStatus());
        return ResponseEntity.ok(response);
    }

    @GetMapping("/{id}/transitions")
    public ResponseEntity<TransitionResponse> getTransitions(@PathVariable Long id) {
        TransitionResponse response = stateMachineService.getAvailableTransitions(id);
        return ResponseEntity.ok(response);
    }

    @ExceptionHandler(IllegalStateException.class)
    public ResponseEntity<ErrorResponse> handleIllegalState(IllegalStateException ex) {
        return ResponseEntity.status(HttpStatus.BAD_REQUEST).body(new ErrorResponse(ex.getMessage()));
    }

    @ExceptionHandler(IllegalArgumentException.class)
    public ResponseEntity<ErrorResponse> handleIllegalArgument(IllegalArgumentException ex) {
        return ResponseEntity.status(HttpStatus.BAD_REQUEST).body(new ErrorResponse(ex.getMessage()));
    }
}

